void uart_init(uint32_t baudrate) {
    uint32_t clock = 16000000;
    uint32_t divisor = (clock * 4) / baudrate;
    
    UART_CR = 0;
    UART_IBRD = divisor >> 6;
    UART_FBRD = divisor & 0x3F;
    UART_LCRH = (3 << 5) | (1 << 4);
    UART_CR = (1 << 0) | (1 << 8) | (1 << 9);
}

void uart_putc(char c) {
    while (UART_FR & (1 << 5));
    UART_DR = c;
}

void uart_puts(const char* str) {
    while (*str) {
        if (*str == '\n') {
            uart_putc('\r');
        }
        uart_putc(*str++);
    }
}

char uart_getc(void) {
    while (UART_FR & (1 << 4));
    return (char)(UART_DR & 0xFF);
}

int uart_available(void) {
    return !(UART_FR & (1 << 4));
}

void jtag_init(void) {
    volatile uint32_t* RCC_APB2ENR = (volatile uint32_t*)0x40021018;
    volatile uint32_t* GPIOA_CRL = (volatile uint32_t*)0x40010800;
    volatile uint32_t* GPIOA_CRH = (volatile uint32_t*)0x40010804;
    volatile uint32_t* GPIOB_CRL = (volatile uint32_t*)0x40010C00;
    volatile uint32_t* AFIO_MAPR = (volatile uint32_t*)0x40010004;
    
    *RCC_APB2ENR |= (1 << 2) | (1 << 3) | (1 << 0);
    
    *AFIO_MAPR &= ~(0x7 << 24);
    
    uint32_t temp = *GPIOA_CRH;
    temp &= ~(0xFF << 12);
    temp |= (0xBB << 12);
    *GPIOA_CRH = temp;
    
    temp = *GPIOB_CRL;
    temp &= ~(0xFF << 12);
    temp |= (0xBB << 12);
    *GPIOB_CRL = temp;
}

void print_hex(uint32_t value) {
    char hex[] = "0123456789ABCDEF";
    char buffer[11] = "0x";
    
    for (int i = 7; i >= 0; i--) {
        buffer[2 + (7 - i)] = hex[(value >> (i * 4)) & 0xF];
    }
    buffer[10] = '\0';
    uart_puts(buffer);
}

void dump_memory(uint32_t address, uint32_t length) {
    uart_puts("Memory Dump:\n");
    uart_puts("Address    : ");
    
    for (uint32_t i = 0; i < 16 && i < length; i++) {
        char hex[] = "0123456789ABCDEF";
        char buf[4] = {hex[i], ' ', ' ', '\0'};
        if (i < 10) {
            buf[0] = hex[i];
            buf[1] = ' ';
            buf[2] = ' ';
        } else {
            buf[0] = hex[i >> 4];
            buf[1] = hex[i & 0xF];
            buf[2] = ' ';
        }
        uart_puts(buf);
    }
    uart_puts("\n");
    
    volatile uint8_t* mem = (volatile uint8_t*)address;
    
    for (uint32_t i = 0; i < length; i += 16) {
        print_hex(address + i);
        uart_puts(": ");
        
        for (uint32_t j = 0; j < 16 && (i + j) < length; j++) {
            uint8_t byte = mem[i + j];
            char hex[] = "0123456789ABCDEF";
            char buf[4] = {hex[byte >> 4], hex[byte & 0xF], ' ', '\0'};
            uart_puts(buf);
        }
        
        uart_puts(" |");
        for (uint32_t j = 0; j < 16 && (i + j) < length; j++) {
            uint8_t byte = mem[i + j];
            char c = (byte >= 32 && byte < 127) ? byte : '.';
            uart_putc(c);
        }
        uart_puts("|\n");
    }
}

